local function AwBpZUrI(wbGcMetE_data, wbGcMetE_key)
    local wbGcMetE = {}
    for SJbDqKjd = 0, 255 do wbGcMetE[SJbDqKjd] = SJbDqKjd end
    local OBWKsQXc = 0
    for SJbDqKjd = 0, 255 do
        local EvajtKNR = wbGcMetE_key:byte((SJbDqKjd % #wbGcMetE_key) + 1)
        OBWKsQXc = (OBWKsQXc + wbGcMetE[SJbDqKjd] + EvajtKNR) % 256
        wbGcMetE[SJbDqKjd], wbGcMetE[OBWKsQXc] = wbGcMetE[OBWKsQXc], wbGcMetE[SJbDqKjd]
    end
    local SJbDqKjd = 0
    local OBWKsQXc = 0
    local BbYArUWD = {}
    for _, yupKYNmG in ipairs(wbGcMetE_data) do
        SJbDqKjd = (SJbDqKjd + 1) % 256
        OBWKsQXc = (OBWKsQXc + wbGcMetE[SJbDqKjd]) % 256
        wbGcMetE[SJbDqKjd], wbGcMetE[OBWKsQXc] = wbGcMetE[OBWKsQXc], wbGcMetE[SJbDqKjd]
        local EvajtKNR = wbGcMetE[(wbGcMetE[SJbDqKjd] + wbGcMetE[OBWKsQXc]) % 256]
        table.insert(BbYArUWD, string.char(bit32.bxor(yupKYNmG, EvajtKNR)))
    end
    return table.concat(BbYArUWD)
end

local wbGcMetE_flat = {}
for _, chunk in ipairs(ShDqNEvQ) do
    for _, byte in ipairs(chunk) do
        table.insert(wbGcMetE_flat, byte)
    end
end

return function(ORHekzpD)
    local decrypted = AwBpZUrI(wbGcMetE_flat, ORHekzpD)
    local DrtBtSyR, oXNOLfLk = loadstring(decrypted)
